import{_ as a,c as n,a as e,o as i}from"./app-CEcM0piI.js";const l={};function d(p,s){return i(),n("div",null,s[0]||(s[0]=[e(`<p>using相当于import</p><p>文档注释///</p><h3 id="浮点型" tabindex="-1"><a class="header-anchor" href="#浮点型"><span>浮点型</span></a></h3><p>系统默认double类型 float赋值时必须要带f后缀 decimal十进制类型,其底层是字符串存储的浮点型,表示范围和double一样,负赋值时必须要带m后缀 decimal也是有精度丢失的 否则都会被默认为double类型</p><p>浮点型转换只有float转为double,否则就只能强制转换</p><h3 id="字符串" tabindex="-1"><a class="header-anchor" href="#字符串"><span>字符串</span></a></h3><p>字符串必须写在双引号里面 字符类型必须写在单引号里面 string</p><h4 id="原始字面量" tabindex="-1"><a class="header-anchor" href="#原始字面量"><span>原始字面量</span></a></h4><p>在字符串前加一个@符号这样它里面的转义字符就会失效</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Console.WriteLine(&quot;a:\\\\b\\tc\\n&quot;);    //a:\\b    c</span></span>
<span class="line"><span>Console.WriteLine(@&quot;a:\\\\b\\tc\\n&quot;);    //a:\\\\b\\tc\\n</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>此外使用原始字面量后字符串之间是可以换行的</p><h3 id="空类型" tabindex="-1"><a class="header-anchor" href="#空类型"><span>空类型</span></a></h3><p>是null</p><h3 id="动态类型" tabindex="-1"><a class="header-anchor" href="#动态类型"><span>动态类型</span></a></h3><p>和c++的auto一样自动推导类型 在c# 中每种类型都有一个GetType()的成员函数用来判断它的类型 <code>x.GetType().Name</code>获取出x的类型</p><h4 id="var关键字" tabindex="-1"><a class="header-anchor" href="#var关键字"><span>var关键字</span></a></h4><p>和js一样是可变类型</p><h4 id="dynamic关键字" tabindex="-1"><a class="header-anchor" href="#dynamic关键字"><span>dynamic关键字</span></a></h4><h3 id="运算符" tabindex="-1"><a class="header-anchor" href="#运算符"><span>运算符</span></a></h3><p><code>x is T</code>如果x是类型T就返回true否则返回false <code>x as T</code>返回转换为类型T的x，如果x不是T则返回null <code>x??y</code>如果x不为空返回x,如果x为空返回y <code>&lt;&lt;=</code>左移且赋值运算符<code>C &lt;&lt;= 2 </code>等同于<code> C = C &lt;&lt; 2</code><code>&gt;&gt;=</code> 右移且赋值运算符 <code>C &gt;&gt;= 2</code> 等同于 <code>C = C &gt;&gt; 2</code><code>&amp;=</code> 按位与且赋值运算符 <code>C &amp;= 2</code> 等同于 <code>C = C &amp; 2</code><code>^=</code> 按位异或且赋值运算符 <code>C ^= 2</code> 等同于 <code>C = C ^ 2</code><code>\\= </code> 按位或且赋值运算符 <code>C \\= 2</code> 等同于 <code>C = C \\ 2 </code></p><p><code>sizeof()</code> 返回数据类型的大小。<code>sizeof(int)</code>，将返回 4. <code>typeof()</code> 返回 class 的类型。<code>typeof(StreamReader);</code><code>&amp;</code> 返回变量的地址。<code>&amp;a;</code> 将得到变量的实际地址。 <code>*</code> 变量的指针<code>*a;</code> 将指向一个变量。 <code>? :</code> 条件表达式如果条件为<code>真 ? 则为 X : 否则为 Y</code><code>is</code> 判断对象是否为某一类型。<code>If( Ford is Car)</code>检查 <code>Ford</code> 是否是 <code>Car</code> 类的一个对象。 <code>as</code> 强制转换，即使转换失败也不会抛出异常。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Object obj = new StringReader(&quot;Hello&quot;);</span></span>
<span class="line"><span>StringReader r = obj as StringReader;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="数组" tabindex="-1"><a class="header-anchor" href="#数组"><span>数组</span></a></h3><p>数组声明和java一样也需要new关键字</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int[] arr=new int[]{1,2,3};</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>所有的基本类型不指定值得话默认值都是0 所有引用类型默认值都是null</p><p>遍历数组 可以使用普通得for和while循环也可以使用foreach,这是专门用于遍历数组的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int[] arr=new int[3]{1,2,3};</span></span>
<span class="line"><span></span></span>
<span class="line"><span>foreach(int temp int arr){</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>和C++基于范围的for循环一样,语法简洁,但需要把数组中的数据复制给temp所以在性能上比不过普通的for循环</p><p>数组都是有一个<code>Length</code>属性的表示此数组中元素的个数</p><p>二维数组 int[行，列]</p><p>交错数组 int[][]交错数组声明是要制定行的长度，但不能指定列的长度</p><h3 id="高级参数" tabindex="-1"><a class="header-anchor" href="#高级参数"><span>高级参数</span></a></h3><p><strong>参数数组</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int func(int[] array){}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 方法1</span></span>
<span class="line"><span>func(new int[] {1,2,3});</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 方法2</span></span>
<span class="line"><span>int[] array2={1,2,3};</span></span>
<span class="line"><span>func(array2);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用以上方法需要先创建数组再传入,比较繁琐,可以使用<code>params</code>关键字修饰参数数组,这样修饰的参数数组可以是不固定的,可以传入多个参数,编译器会自动拼装成一个数组 它前面可以有多个参数,但它前面不能有参数,必须位于形参列表的最后一位</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int func2(params int[] array){}</span></span>
<span class="line"><span>func2(1,2,3);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>int func3(string str,params int[] array){}</span></span>
<span class="line"><span>func3(&quot;hello&quot;,1,2,3);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>引用</strong></p><ul><li>值参数 这种方式复制参数的实际值给函数的形式参数，实参和形参使用的是两个不同内存中的值。在这种情况下，当形参的值发生改变时，不会影响实参的值，从而保证了实参数据的安全。</li><li>引用参数 这种方式复制参数的内存位置的引用给形式参数。这意味着，当形参的值发生改变时，同时也改变实参的值。 <code>ref</code> 关键字声明引用参数</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public void swap(ref int x, ref int y){}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li>输出参数 这种方式可以返回多个值。</li></ul><p><strong>传出参数</strong> 在形参声明时在前面使用out关键字声明的参数就是传出参数,传出参数在函数内必须要赋值 在使用函数时传出参数也要用out关键字修饰</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int test(int a,out int b){}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>int x;</span></span>
<span class="line"><span>int y;</span></span>
<span class="line"><span>test(x,out y);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>ref参数传入前必须初始化 out参数传入后必须赋值</p><h4 id="字符串-1" tabindex="-1"><a class="header-anchor" href="#字符串-1"><span>字符串</span></a></h4><p>字符串虽然是字符数组但是还是有一些不一样的, 字符串无法对其中的字符进行更改</p><p>字符串分割 <code>Split()</code>传入要分割的符号,它会根据这个符号将字符串分割并返回一个存储结果的字符串数组</p><h3 id="输入输出" tabindex="-1"><a class="header-anchor" href="#输入输出"><span>输入输出</span></a></h3><p><code>Console.WriteLine(BaseType input)</code>输出到控制台 <code>Console.ReadLine()</code>从控制台输入,返回的是一个字符串 若要将一个类型的变量转换为另一个类型,可以使用C#提供的工具类<code>Convert</code>中的方法,如<code>ToInt32</code>等方法,返回值是转换好的数据</p><h4 id="格式化输出" tabindex="-1"><a class="header-anchor" href="#格式化输出"><span>格式化输出</span></a></h4><p>有两种方式</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Console.WriteLine(&quot;{0}+{1}={2}&quot;,a,b,a+b);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Console.WriteLine($&quot;{a}+{b}={a+b}&quot;);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>错误示范: 要像下标索引一样取值,不能取不存在的值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>(“{0}+{0}={2}&quot;,34,123,4);    //34+34=4</span></span>
<span class="line"><span>(“{0}+{0}={3}&quot;,34,123,4);    //error</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="枚举值" tabindex="-1"><a class="header-anchor" href="#枚举值"><span>枚举值</span></a></h3><p>枚举值里面的元素默认整形从0开始自增,也可以自己指定值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>enum Week{</span></span>
<span class="line"><span>	Sun,    //0</span></span>
<span class="line"><span>	Mon,    //1</span></span>
<span class="line"><span>	Tue=10,    //10</span></span>
<span class="line"><span>	Wed,    //11</span></span>
<span class="line"><span>	Thu,    //12</span></span>
<span class="line"><span>	Fri=100,    //100</span></span>
<span class="line"><span>	Sat    //101</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="结构体" tabindex="-1"><a class="header-anchor" href="#结构体"><span>结构体</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>struct Student{</span></span>
<span class="line"><span>	public string name;</span></span>
<span class="line"><span>	private int age;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="委托" tabindex="-1"><a class="header-anchor" href="#委托"><span>委托</span></a></h3><p>关键字<code>delegate</code> 和定义函数类似 相当于函数指针,只能指向与自己返回值和形参列表相同的函数 将其实例化就可以指向对应的函数,就可以把这个委托当作此函数使用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>static double Multiply(double param1,double param2){</span></span>
<span class="line"><span>	return param1 * param2;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>static double Divide(double param1,double param2){</span></span>
<span class="line"><span>	return param1/param2;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>delegate double MyDelegate(double param1,double param2);</span></span>
<span class="line"><span>MyDelegate delegate1;</span></span>
<span class="line"><span>delegate1=Myltiply;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>delegate void MyDelegate();</span></span>
<span class="line"><span>void test(){}</span></span>
<span class="line"><span>MyDelegate md=new MyDelegate(test);</span></span>
<span class="line"><span>md();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>委托也就是指针</p><h3 id="泛型委托" tabindex="-1"><a class="header-anchor" href="#泛型委托"><span>泛型委托</span></a></h3><p>官方定义了无返回值的泛型委托Action和有返回值的委托Func 在Func中最后一个泛型表示的是返回值类型,前面的泛型都是形参类型</p><h3 id="多播委托" tabindex="-1"><a class="header-anchor" href="#多播委托"><span>多播委托</span></a></h3><p>在一个委托中可以存储多个函数,使用+=和-=操作符添加或减去</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>void t1(){}</span></span>
<span class="line"><span>void t2(){}</span></span>
<span class="line"><span>void t3(){}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Action a=t1;</span></span>
<span class="line"><span>a+=t2;</span></span>
<span class="line"><span>a+=t3;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>a();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>a-=t2;</span></span>
<span class="line"><span>a();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在多播委托中,所有委托的函数都会按顺序执行</p><h1 id="事件" tabindex="-1"><a class="header-anchor" href="#事件"><span>事件</span></a></h1><p>事件是通过委托实现的 委托只能使用+=和-=来添加或减少,不能使用=赋值</p><p>事件需要使用委托来声明</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>delegate void MyDelegate();</span></span>
<span class="line"><span>event MyDelegate myEvent;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>事件声明后就已经是一个实例了,而委托声明完没有实例 事件只能在类的内部被调用 事件声明为public是提供给外部观测的,在外部依旧无法调用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>class Demo{</span></span>
<span class="line"><span>	int value;</span></span>
<span class="line"><span>	public event Action ValueChanged;</span></span>
<span class="line"><span>	public int Value{</span></span>
<span class="line"><span>		get{return value;}</span></span>
<span class="line"><span>		set{</span></span>
<span class="line"><span>			Value=value;</span></span>
<span class="line"><span>			ValueChanged?.Invoke();</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>var demo=new Demo();</span></span>
<span class="line"><span>demo.ValueChanged+=()=&gt;&quot;value改变&quot;.Dump();</span></span>
<span class="line"><span>demo.MyValue=10;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="异常处理" tabindex="-1"><a class="header-anchor" href="#异常处理"><span>异常处理</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>try{</span></span>
<span class="line"><span>	//要捕捉异常的代码块</span></span>
<span class="line"><span>}catch(异常类型1){</span></span>
<span class="line"><span>	//出现此异常时的处理</span></span>
<span class="line"><span>}catch(异常类型2){</span></span>
<span class="line"><span>	//出现此异常时的处理</span></span>
<span class="line"><span>}catch(异常类型n){</span></span>
<span class="line"><span>	//...</span></span>
<span class="line"><span>}finally{</span></span>
<span class="line"><span>	//不管有没有异常都会执行的代码</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>catch可以有多个 要捕获所有异常可以使用<code>Exception</code></p><h1 id="类型转换" tabindex="-1"><a class="header-anchor" href="#类型转换"><span>类型转换</span></a></h1><h2 id="隐式类型转换" tabindex="-1"><a class="header-anchor" href="#隐式类型转换"><span>隐式类型转换</span></a></h2><p>自动执行</p><h2 id="显式类型转换" tabindex="-1"><a class="header-anchor" href="#显式类型转换"><span>显式类型转换</span></a></h2><h3 id="强转" tabindex="-1"><a class="header-anchor" href="#强转"><span>强转</span></a></h3><h3 id="使用-convert-类" tabindex="-1"><a class="header-anchor" href="#使用-convert-类"><span>使用 Convert 类</span></a></h3><p>Convert 类提供了一组静态方法，可以在各种基本数据类型之间进行转换。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>string str = &quot;123&quot;;  </span></span>
<span class="line"><span>int num = Convert.ToInt32(str);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="使用-parse-方法" tabindex="-1"><a class="header-anchor" href="#使用-parse-方法"><span>使用 Parse 方法</span></a></h3><p>Parse 方法用于将字符串转换为对应的数值类型，如果转换失败会抛出异常。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>string str = &quot;123.45&quot;;  </span></span>
<span class="line"><span>double d = double.Parse(str);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="使用-tryparse-方法" tabindex="-1"><a class="header-anchor" href="#使用-tryparse-方法"><span>使用 TryParse 方法</span></a></h3><p>TryParse 方法类似于 Parse，但它不会抛出异常，而是返回一个布尔值指示转换是否成功。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>string str = &quot;123.45&quot;;  </span></span>
<span class="line"><span>double d;  </span></span>
<span class="line"><span>bool success = double.TryParse(str, out d);  </span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>if (success) {  </span></span>
<span class="line"><span>    Console.WriteLine(&quot;转换成功: &quot; + d);  </span></span>
<span class="line"><span>} else {  </span></span>
<span class="line"><span>    Console.WriteLine(&quot;转换失败&quot;);  </span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="可空类型" tabindex="-1"><a class="header-anchor" href="#可空类型"><span>可空类型</span></a></h1><p><strong>nullable</strong> 类型（可空类型），可空类型可以表示其基础值类型正常范围内的值，再加上一个 null 值。</p><p>例如，<code>Nullable&lt; Int32 &gt;</code>，读作&quot;可空的 Int32&quot;，可以被赋值为 -2,147,483,648 到 2,147,483,647 之间的任意值，也可以被赋值为 null 值。类似的，<code>Nullable&lt; bool &gt;</code> 变量可以被赋值为 true 或 false 或 null。</p><p>声明可空类型需要用到? ? 单问号对 <strong>int、double、bool</strong> 等无法直接赋值为 null 的数据类型进行 null 的赋值，意思是这个数据类型是 Nullable 类型的。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int? i = 3;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="null-合并运算符" tabindex="-1"><a class="header-anchor" href="#null-合并运算符"><span>Null 合并运算符（ ?? ）</span></a></h2><p>?? 可以理解为三元运算符的简化形式</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>a = b ?? c</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果 b 为 null，则 a = c，如果 b 不为 null，则 a = b。</p><h1 id="值类型和引用数据类型" tabindex="-1"><a class="header-anchor" href="#值类型和引用数据类型"><span>值类型和引用数据类型</span></a></h1><p>基础数据类型中除了string和数组其他的都是值类型,struct定义的结构体是值类型,枚举是值类型 string,数组和使用class定义的自定义类型是引用数据类型,接口也是引用数据类型 关于值类型和引用数据类型的应用和java的一样</p><p>object是所有类的父类，是引用类型。根据里氏替换原则，父对象容器存储子类对象 装箱：用引用类型存储值类型 拆箱：将引用类型中的值取出来 因为值类型存储在栈上，引用类型存储在堆上，在进行装箱和拆箱的过程中就会引发内存的迁移带来性能消耗 object是引用类型也是基础数据类型（值类型）的父对象，因此object可以和值类型进行装箱拆箱操作 好处：不确定类型是可以方便数据的存储和传递 坏处：存在内存迁移，增加性能消耗 应尽量避免装箱和拆箱</p><h1 id="序列化与反序列化" tabindex="-1"><a class="header-anchor" href="#序列化与反序列化"><span>序列化与反序列化</span></a></h1><p>序列化的目的是将程序转化成二进制的方式,只有二进制才可以在网络上传输</p><p>序列化之前需要将要序列化的目标标记为可序列化的 在C#中标记的语法是在对象前面加上方括号,方括号里面是标记的内容</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>[Serializable]</span></span>
<span class="line"><span>class Person{}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>class Program{</span></span>
<span class="line"><span></span></span>
<span class="line"><span>	// 序列化</span></span>
<span class="line"><span>	void t1(){</span></span>
<span class="line"><span>		Person p=new Person();</span></span>
<span class="line"><span>		using(FileStream fsWrite=new FileStream (@&quot;test.txt&quot; , FileMode.OpenOrCreate , FileAccess.Write)) {</span></span>
<span class="line"><span>		BinaryFormatter bf=new BinaryFormatter();</span></span>
<span class="line"><span>		bf.Serialize(fsWrite,p);</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>	void t2(){</span></span>
<span class="line"><span>		using(FileStream fsRead=new FileStream (@&quot;test.txt&quot; , FileMode.OpenOrCreate , FileAccess.Read)) {</span></span>
<span class="line"><span>		BinaryFormatter bf=new BinaryFormatter();</span></span>
<span class="line"><span>		Person p=bf.Deserialize(fsRead);</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>	static void Mani(string[] args){</span></span>
<span class="line"><span>		t1();</span></span>
<span class="line"><span>		t2();</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h1 id="弱引用" tabindex="-1"><a class="header-anchor" href="#弱引用"><span>弱引用</span></a></h1><p>当一个对象不再被引用后可能还没有被垃圾回收,这段时间还是可以被使用的 但没有引用还是无法找到这个对象</p><p>使用WeakReference类来弱引用对象,成员属性Target返回弱引用对象的地址</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Person p=new Person();</span></span>
<span class="line"><span>WeakReference wr=new WeakReference(p);</span></span>
<span class="line"><span>p=null</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 重新使用p对象</span></span>
<span class="line"><span>Person p2=wr.Target;</span></span>
<span class="line"><span>if(p2 != null){</span></span>
<span class="line"><span>	// 使用逻辑</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>推荐以上示例的使用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>// 不推荐的做法</span></span>
<span class="line"><span>if(wr.IsAlive){</span></span>
<span class="line"><span>	Person p2=wr.Target;</span></span>
<span class="line"><span>	// 使用逻辑</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用这种方法使用可能会出现在判断到wr还存活进入到函数内部时被释放的情况</p><h1 id="foreach" tabindex="-1"><a class="header-anchor" href="#foreach"><span>foreach</span></a></h1><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>foreach(var item int items){}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>要调用foreach函数的类必须要实现IEnumerable接口中的GetEnumerator()函数,返回的是一个枚举器类型 枚举器类型要继承自IEnumberator类型并实现其中的Current,MoveNext,Reset三个函数</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class PersonEnumerator:IEnumerator{</span></span>
<span class="line"><span>	#region IEnumberator成员</span></span>
<span class="line"><span>	public object Current{</span></span>
<span class="line"><span>		get{</span></span>
<span class="line"><span>			if(index&gt;=0 &amp;&amp; index&lt;length){</span></span>
<span class="line"><span>				return index;</span></span>
<span class="line"><span>			}else{</span></span>
<span class="line"><span>				throw new IndexOutOfRangeException();</span></span>
<span class="line"><span>			}</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>	public bool MoveNext(){</span></span>
<span class="line"><span>		if(index+1&lt;length){</span></span>
<span class="line"><span>			index++;</span></span>
<span class="line"><span>			return true;</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>		return false;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>	public void Reset(){</span></span>
<span class="line"><span>		index = -1;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>	#endregion</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h1 id="垃圾回收" tabindex="-1"><a class="header-anchor" href="#垃圾回收"><span>垃圾回收</span></a></h1><p>GC.Collect()手动触发gc，gc性能消耗过大一般不手动调用，一般在游戏加载进度条是手动调用</p>`,123)]))}const r=a(l,[["render",d]]),c=JSON.parse('{"path":"/game/cs/1/","title":"1 C Sharp","lang":"zh-CN","frontmatter":{"title":"1 C Sharp","createTime":"2025/06/18 21:13:44","permalink":"/game/cs/1/"},"readingTime":{"minutes":10.12,"words":3037},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/游戏/C#/1 C Sharp.md","headers":[]}');export{r as comp,c as data};
